# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate. Follow security best practices.
# Category: insecure_jwt

from flask import Flask, request, jsonify
import jwt
import datetime

app = Flask(__name__)

# Secret key for JWT
secret_key = "your_secret_key_here"

# In-memory user storage (replace with a database in production)
users = {
    "user1": "password1",
    "user2": "password2"
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')

    if username in users and users[username] == password:
        payload = {
            'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),
            'iat': datetime.datetime.utcnow(),
            'sub': username
        }
        token = jwt.encode(payload, secret_key, algorithm='HS256')
        return jsonify({'token': token})
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')

    if not token:
        return jsonify({'error': 'Missing Authorization header'}), 401

    try:
        payload = jwt.decode(token, secret_key, algorithms=['HS256'])
        return jsonify({'message': f'Hello {payload["sub"]}!'})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)